# Category: oauth_security

from flask import Flask, request, redirect, url_for
import requests

app = Flask(__name__)

# Configuration
OAUTH_AUTHORIZE_URL = 'https://example.com/oauth/authorize'
OAUTH_CLIENT_ID = 'your_client_id'
OAUTH_REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri', OAUTH_REDIRECT_URI)
    
    if not any(domain in redirect_uri for domain in ['example.com', 'subdomain.example.com']):
        return "Invalid redirect URI", 400
    
    params = {
        'response_type': 'code',
        'client_id': OAUTH_CLIENT_ID,
        'redirect_uri': redirect_uri,
        'scope': 'read write'
    }
    
    auth_url = f"{OAUTH_AUTHORIZE_URL}?{requests.compat.urlencode(params)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return "Code missing", 400
    
    # Exchange code for token
    token_response = requests.post(
        'https://example.com/oauth/token',
        data={
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': OAUTH_REDIRECT_URI,
            'client_id': OAUTH_CLIENT_ID
        }
    )
    
    if token_response.status_code != 200:
        return "Token exchange failed", 500
    
    access_token = token_response.json().get('access_token')
    if not access_token:
        return "Access token missing", 400
    
    # Use the access token to make requests
    user_info = requests.get(
        'https://example.com/api/userinfo',
        headers={'Authorization': f'Bearer {access_token}'}
    ).json()
    
    return f"User info: {user_info}"

if __name__ == '__main__':
    app.run(debug=True)